private data class TopMenuItem(
    val label: String,
    val path: String,
    val children: List<Pair<String, String>> = emptyList(),
)

val HeaderMenuItemStyle = CssStyle {
    base {
        Modifier
            .height(5.2.cssRem)
            .display(DisplayStyle.Flex)
            .justifyContent(JustifyContent.Center)
            .alignItems(AlignItems.Center)
            .borderBottom(3.px, LineStyle.Solid, Colors.Transparent)
    }
    hover {
        Modifier.borderBottom(3.px, LineStyle.Solid, colorMode.toSitePalette().ui.logoAccent)
    }
}

@Composable
private fun HeaderMenuLink(path: String, text: String, color: Color) {
    Link(
        path = path,
        text = text,
        modifier = HeaderMenuItemStyle.toModifier()
            .fontSize(1.05.cssRem)
            .fontWeight(FontWeight.Medium)
            .color(color)
            .padding(leftRight = 1.3.cssRem),
        variant = UndecoratedLinkVariant.then(UncoloredLinkVariant)
    )
}

@Composable
private fun HeaderMenuItem(item: TopMenuItem, color: Color, accent: Color) {
    var expanded by remember { mutableStateOf(false) }

    Column(
        Modifier
            .position(Position.Relative)
            .onMouseEnter { expanded = true }
            .onMouseLeave { expanded = false }
    ) {
        HeaderMenuLink(item.path, item.label, color)

        if (item.children.isNotEmpty() && expanded) {
            Column(
                Modifier
                    .position(Position.Absolute)
                    .top(5.2.cssRem)
                    .left(0.px)
                    .minWidth(10.cssRem)
                    .backgroundColor(Color.rgba(255, 255, 255, 0.86f))
                    .border(1.px, LineStyle.Solid, accent)
                    .padding(topBottom = 0.35.cssRem)
                    .zIndex(200)
            ) {
                item.children.forEach { (label, path) ->
                    Link(
                        path = path,
                        text = label,
                        modifier = Modifier
                            .padding(topBottom = 0.5.cssRem, leftRight = 0.9.cssRem)
                            .fontSize(0.95.cssRem)
                            .color(color),
                        variant = UndecoratedLinkVariant.then(UncoloredLinkVariant)
                    )
                }
            }
        }
    }
}

@Composable
fun NavHeader() {
    val palette = ColorMode.current.toSitePalette()
    var scrollY by remember { mutableStateOf(0.0) }

    DisposableEffect(Unit) {
        val listener = EventListener { _: Event -> scrollY = window.scrollY }
        window.addEventListener("scroll", listener)
        scrollY = window.scrollY
        onDispose { window.removeEventListener("scroll", listener) }
    }

    val progress = (min(80.0, max(0.0, scrollY)) / 80.0).toFloat()
    val headerAlpha = 1f - (0.18f * progress)

    val menus = listOf(
        TopMenuItem("홈", "/", listOf()),
        TopMenuItem("교육원", "/contact", listOf("연락처" to "/contact", "오시는 길" to "/directions")),
        TopMenuItem(Config.COMPANY_NAME, "https://www.d-air.co.kr/"),
    )

    Column(
        Modifier
            .fillMaxWidth()
            .position(Position.Fixed)
            .top(0.px)
            .left(0.px)
            .right(0.px)
            .zIndex(100)
            .backgroundColor(Color.rgba(255, 255, 255, headerAlpha))
            .borderBottom(1.px, LineStyle.Solid, palette.ui.headerBorder)
    ) {
        Row(
            Modifier
                .fillMaxWidth()
                .height(5.2.cssRem)
                .padding(leftRight = 1.5.cssRem),
            verticalAlignment = Alignment.CenterVertically
        ) {
            Row(
                Modifier
                    .fontSize(1.7.cssRem)
                    .fontWeight(FontWeight.Bold)
                    .color(palette.ui.logoPrimary)
                    .onClick { window.location.href = "/" },
                verticalAlignment = Alignment.CenterVertically
            ) {
                SpanText(Config.SITE_NAME.take(2))
                SpanText(Config.SITE_NAME.drop(2), modifier = Modifier.color(palette.ui.logoAccent))
            }

            Spacer()

            Row(
                Modifier.flexWrap(FlexWrap.Wrap),
                verticalAlignment = Alignment.CenterVertically
            ) {
                menus.forEach { item ->
                    HeaderMenuItem(item, palette.ui.navText, palette.ui.logoAccent)
                }
            }
        }
    }
}
