private const val KAKAO_SDK_SCRIPT_ID = "kakao-map-sdk"

private fun newKakaoLatLng(lat: Double, lng: Double): dynamic = js("new window.kakao.maps.LatLng(lat, lng)")
private fun newKakaoMap(container: dynamic, options: dynamic): dynamic = js("new window.kakao.maps.Map(container, options)")
private fun newKakaoMarker(options: dynamic): dynamic = js("new window.kakao.maps.Marker(options)")
private fun newKakaoCustomOverlay(options: dynamic): dynamic = js("new window.kakao.maps.CustomOverlay(options)")

private fun loadKakaoMapSdk(onLoaded: () -> Unit, onError: (String) -> Unit) {
    val appKey = Config.KAKAO_MAP_JS_KEY
    if (appKey.isBlank()) {
        onError("KAKAO_MAP_JS_KEY가 비어 있습니다.")
        return
    }

    val win = js("window")
    val existingKakao = win.kakao
    if (existingKakao != undefined && existingKakao.maps != undefined) {
        existingKakao.maps.load { onLoaded() }
        return
    }

    val existingScript = document.getElementById(KAKAO_SDK_SCRIPT_ID) as? HTMLScriptElement
    if (existingScript != null) {
        existingScript.onload = {
            val kakao = js("window.kakao")
            if (kakao != undefined && kakao.maps != undefined) {
                kakao.maps.load { onLoaded() }
            } else {
                onError("카카오 SDK 로드 후 kakao.maps 객체를 찾지 못했습니다.")
            }
        }
        existingScript.onerror = { _, _, _, _, _ ->
            onError("카카오 SDK 스크립트 로드 실패")
        }
        return
    }

    val script = (document.createElement("script") as HTMLScriptElement).apply {
        id = KAKAO_SDK_SCRIPT_ID
        async = true
        src = "https://dapi.kakao.com/v2/maps/sdk.js?appkey=$appKey&autoload=false"
        onload = {
            val kakao = js("window.kakao")
            if (kakao != undefined && kakao.maps != undefined) {
                kakao.maps.load { onLoaded() }
            } else {
                onError("카카오 SDK 로드 후 kakao.maps 객체를 찾지 못했습니다.")
            }
        }
        onerror = { _, _, _, _, _ ->
            onError("카카오 SDK 스크립트 로드 실패")
        }
    }
    document.head?.appendChild(script)
}

@Composable
fun KakaoMapBox() {
    var errorMessage by remember { mutableStateOf<String?>(null) }

    DisposableEffect(Unit) {
        loadKakaoMapSdk(onLoaded = {
            val container = document.getElementById("kakao-map")
            val kakao = js("window.kakao")
            if (container != null && kakao != undefined && kakao.maps != undefined) {
                val center = newKakaoLatLng(36.257370, 126.920300)
                val options = js("{}")
                options.center = center
                options.level = 3
                val map = newKakaoMap(container, options)

                val markerOptions = js("{}")
                markerOptions.position = center
                newKakaoMarker(markerOptions).setMap(map)

                val labelOptions = js("{}")
                labelOptions.position = center
                labelOptions.yAnchor = 1.9
                labelOptions.content = """
                    <div style="
                        background: rgba(255,255,255,0.96);
                        border: 1px solid #d9d9d9;
                        border-radius: 8px;
                        padding: 6px 10px;
                        font-size: 13px;
                        font-weight: 600;
                        white-space: nowrap;
                        box-shadow: 0 1px 4px rgba(0,0,0,0.16);
                    ">
                        ${Config.ADDRESS}
                    </div>
                """.trimIndent()
                newKakaoCustomOverlay(labelOptions).setMap(map)
            }
        }, onError = { message ->
            errorMessage = message
            console.error("KakaoMapBox: $message")
        })
        onDispose { }
    }

    if (errorMessage == null) {
        Div(
            attrs = Modifier
                .id("kakao-map")
                .fillMaxWidth()
                .height(26.cssRem)
                .toAttrs()
        )
    } else {
        Div(
            attrs = Modifier
                .fillMaxWidth()
                .height(26.cssRem)
                .padding(1.cssRem)
                .toAttrs {
                    style {
                        property("display", "flex")
                        property("align-items", "center")
                        property("justify-content", "center")
                        property("background", "#f7f8fb")
                        property("color", Color.rgb(0xB00020).toString())
                        property("text-align", "center")
                    }
                }
        ) {
            Text("카카오맵 로드 실패: $errorMessage (도메인 등록/JavaScript 키 확인)")
        }
    }
}
