@InitRoute
fun initContactPage(ctx: InitRouteContext) {
    ctx.data.add(PageLayoutData("연락처"))
}

@Composable
private fun ContactRow(label: String, content: @Composable () -> Unit) {
    Row(Modifier.fillMaxWidth().gap(1.cssRem), verticalAlignment = Alignment.CenterVertically) {
        SpanText(label, Modifier.width(7.cssRem).fontWeight(FontWeight.SemiBold))
        Box(Modifier.fillMaxWidth()) {
            content()
        }
    }
}

@Page("/contact")
@Layout(".components.layouts.PageLayout")
@Composable
fun ContactPage() {
    val ctx = rememberPageContext()
    val palette = ColorMode.current.toSitePalette()

    SubPageScaffold(
        heroTitle = "연락처",
        heroSubtitle = "궁금한 점이 있으시면 편하게 문의해 주세요.",
        heroImageUrl = "https://images.unsplash.com/photo-1524661135-423995f22d0b?auto=format&fit=crop&w=1800&q=80",
        sideTitle = "회사정보",
        sideMenus = listOf(
            SubPageMenuItem("연락처", "/contact", selected = true),
            SubPageMenuItem("찾아오시는길", "/directions", selected = false),
        ),
        contentTitle = "연락처",
        onMenuClick = { item -> ctx.router.tryRoutingTo(item.path) }
    ) {
        Column(
            Modifier
                .fillMaxWidth()
                .border(1.px, LineStyle.Solid, palette.ui.cardBorder)
                .borderRadius(0.6.cssRem)
                .backgroundColor(Color.rgb(0xFCFDFF))
                .padding(1.25.cssRem)
                .gap(0.95.cssRem)
        ) {
            SpanText("아래 연락처로 문의하시면 빠르게 안내드리겠습니다.", Modifier.color(palette.ui.mutedText))
            ContactRow("회사명") { SpanText(Config.COMPANY_NAME) }
            ContactRow("대표이름") { SpanText(Config.CEO) }
            ContactRow("주소") { SpanText(Config.COMPANY_ADDRESS) }
            ContactRow("전화번호") {
                A("tel:${Config.PHONE}", attrs = Modifier.color(palette.ui.navText).toAttrs()) {
                    Text(Config.PHONE)
                }
            }
            ContactRow("이메일") {
                A("mailto:${Config.EMAIL}", attrs = Modifier.color(palette.ui.navText).toAttrs()) {
                    Text(Config.EMAIL)
                }
            }
            ContactRow("회사번호") { SpanText(Config.BUSINESS_NUMBER) }
        }
    }
}
