@Composable
fun Footer(modifier: Modifier = Modifier) {
    val palette = ColorMode.current.toSitePalette()

    Box(
        modifier
            .fillMaxWidth()
            .backgroundColor(palette.ui.footerBackground)
            .padding(topBottom = 1.5.cssRem, leftRight = 1.cssRem)
            .padding(bottom = 1.8.cssRem),
        contentAlignment = Alignment.Center
    ) {
        Column(Modifier.textAlign(TextAlign.Center).color(Colors.White).fontSize(0.88.cssRem).padding(top = 1.cssRem).lineHeight(1.8),
            horizontalAlignment = Alignment.CenterHorizontally) {
            SpanText("회사명: ${Config.COMPANY_NAME} | 대표이름: ${Config.CEO} | 주소: ${Config.COMPANY_ADDRESS}")
            SpanText("전화번호: ${Config.PHONE} | 이메일: ${Config.EMAIL} | 교육원 주소: ${Config.EDU_ADDRESS}")
            SpanText("Copyright © ${Config.SITE_NAME}. All rights reserved")
        }
    }
}
