@InitRoute
fun initHomePage(ctx: InitRouteContext) {
    ctx.data.add(PageLayoutData("안내"))
}

@Composable
private fun QuickActionLink(path: String, label: String, filled: Boolean) {
    val palette = ColorMode.current.toSitePalette()
    Link(
        path = path,
        text = label,
        modifier = Modifier
            .padding(topBottom = 0.7.cssRem, leftRight = 1.2.cssRem)
            .border(1.px, LineStyle.Solid, if (filled) palette.ui.ctaBackground else palette.ui.cardBorder)
            .borderRadius(999.px)
            .backgroundColor(if (filled) palette.ui.ctaBackground else Colors.Transparent)
            .color(if (filled) Colors.White else palette.ui.navText)
            .fontWeight(FontWeight.SemiBold),
        variant = UndecoratedLinkVariant.then(UncoloredLinkVariant)
    )
}

@Page
@Layout(".components.layouts.PageLayout")
@Composable
fun HomePage() {
    val palette = ColorMode.current.toSitePalette()
    val panelBackground = if (ColorMode.current.isLight) Color.rgb(0xFFFFFF) else Color.rgb(0x0E1B2B)

    Box(
        Modifier
            .fillMaxWidth()
            .minHeight(72.vh)
            .padding(topBottom = 3.8.cssRem, leftRight = 1.2.cssRem),
        contentAlignment = Alignment.Center
    ) {
        Column(
            Modifier
                .fillMaxWidth()
                .maxWidth(56.cssRem)
                .backgroundColor(panelBackground)
                .border(1.px, LineStyle.Solid, palette.ui.cardBorder)
                .borderRadius(1.1.cssRem)
                .boxShadow(blurRadius = 1.1.cssRem, color = Color.rgba(0, 0, 0, 0.09f))
                .padding(2.cssRem)
                .gap(0.9.cssRem)
        ) {
            SpanText(
                "SITE NOTICE",
                Modifier
                    .fontSize(0.82.cssRem)
                    .fontWeight(FontWeight.SemiBold)
                    .color(palette.ui.logoAccent)
            )
            SpanText(
                "아직 사이트 개발 중입니다.",
                Modifier
                    .fontSize(2.2.cssRem)
                    .fontWeight(FontWeight.Bold)
                    .lineHeight(1.2)
                    .color(palette.ui.navText)
            )
            SpanText(
                "교육 문의는 하단의 연락처를 통해 확인해 주세요.",
                Modifier.fontSize(1.05.cssRem).lineHeight(1.6).color(palette.ui.mutedText)
            )
            SpanText(
                "빠르게 개발해서 정식 오픈하겠습니다.",
                Modifier.fontSize(1.05.cssRem).lineHeight(1.6).color(palette.ui.mutedText)
            )

            Row(
                Modifier
                    .margin(top = 0.8.cssRem)
                    .gap(0.7.cssRem)
                    .flexWrap(FlexWrap.Wrap),
                horizontalArrangement = Arrangement.Start
            ) {
                QuickActionLink("/contact", "연락처 바로가기", filled = true)
                QuickActionLink("/directions", "오시는 길", filled = false)
            }

            SpanText(
                "연락처 정보를 찾기 어렵다면 페이지 하단 footer에서도 확인할 수 있습니다.",
                Modifier
                    .margin(top = 0.45.cssRem)
                    .fontSize(0.9.cssRem)
                    .color(palette.ui.mutedText)
                    .textAlign(TextAlign.Start)
            )
        }
    }
}
