data class SubPageMenuItem(
    val label: String,
    val path: String,
    val selected: Boolean = false,
)

@Composable
fun SubPageScaffold(
    heroTitle: String,
    heroSubtitle: String,
    heroImageUrl: String,
    sideTitle: String,
    sideMenus: List<SubPageMenuItem>,
    contentTitle: String,
    onMenuClick: (SubPageMenuItem) -> Unit,
    content: @Composable ColumnScope.() -> Unit,
) {
    val palette = ColorMode.current.toSitePalette()

    Column(Modifier.fillMaxWidth()) {
        Box(
            Modifier
                .fillMaxWidth()
                .height(24.vh)
                .minHeight(180.px)
                .position(Position.Relative)
        ) {
            Img(
                src = heroImageUrl,
                attrs = Modifier
                    .position(Position.Absolute)
                    .top(0.px)
                    .right(0.px)
                    .fillMaxSize()
                    .toAttrs { style { property("object-fit", "cover") } }
            )
            Box(Modifier.fillMaxSize().backgroundColor(palette.ui.heroOverlay))
            Column(
                Modifier.fillMaxSize().padding(leftRight = 2.cssRem),
                verticalArrangement = com.varabyte.kobweb.compose.foundation.layout.Arrangement.Center
            ) {
                SpanText(heroTitle, Modifier.color(Colors.White).fontSize(2.cssRem).fontWeight(FontWeight.Bold))
                SpanText(heroSubtitle, Modifier.color(Colors.White).margin(top = 0.5.cssRem))
            }
        }

        Box(
            Modifier
                .fillMaxWidth()
                .backgroundColor(Colors.White)
                .padding(topBottom = 2.8.cssRem, leftRight = 1.4.cssRem)
        ) {
            Row(Modifier.fillMaxWidth().gap(1.6.cssRem).flexWrap(FlexWrap.Wrap)) {
                Column(
                    Modifier
                        .width(22.cssRem)
                        .backgroundColor(Colors.White)
                        .padding(1.2.cssRem)
                ) {
                    SpanText(sideTitle, Modifier.fontSize(2.cssRem).fontWeight(FontWeight.Bold).margin(bottom = 1.cssRem))
                    sideMenus.forEach { item ->
                        SubPageMenuRow(item = item, onClick = { onMenuClick(item) })
                    }
                }

                Column(
                    Modifier
                        .flexGrow(1)
                        .minWidth(24.cssRem)
                        .backgroundColor(Colors.White)
                        .padding(1.2.cssRem)
                ) {
                    Row(
                        Modifier
                            .fillMaxWidth()
                            .borderBottom(1.px, LineStyle.Solid, palette.ui.cardBorder)
                            .padding(bottom = 0.65.cssRem),
                        verticalAlignment = Alignment.Bottom
                    ) {
                        SpanText(contentTitle, Modifier.fontSize(2.cssRem).fontWeight(FontWeight.Bold).color(palette.ui.navText))
                    }
                    Box(
                        Modifier
                            .width(10.5.cssRem)
                            .height(2.px)
                            .backgroundColor(palette.ui.logoAccent)
                            .margin(bottom = 1.4.cssRem)
                    )
                    content()
                }
            }
        }
    }
}

@Composable
private fun SubPageMenuRow(item: SubPageMenuItem, onClick: () -> Unit) {
    val palette = ColorMode.current.toSitePalette()
    Box(
        Modifier
            .fillMaxWidth()
            .borderBottom(1.px, LineStyle.Solid, palette.ui.cardBorder)
            .padding(topBottom = 0.8.cssRem)
            .onClick { onClick() }
    ) {
        SpanText(
            item.label,
            Modifier
                .fontSize(1.1.cssRem)
                .color(if (item.selected) palette.ui.logoAccent else Color.rgb(0x808080))
                .fontWeight(if (item.selected) FontWeight.Bold else FontWeight.Normal)
        )
    }
}
