/**
 * @property nearBackground A useful color to apply to a container that should differentiate itself from the background
 *   but just a little.
 */
class SitePalette(
    val nearBackground: Color,
    val cobweb: Color,
    val brand: Brand,
    val ui: Ui,
) {
    class Brand(
        val primary: Color = Color.rgb(0x3C83EF),
        val accent: Color = Color.rgb(0x5FA7FF),
    )

    class Ui(
        val headerGlass: Color,
        val headerBorder: Color,
        val navText: Color,
        val logoPrimary: Color,
        val logoAccent: Color,
        val sectionBackground: Color,
        val heroOverlay: Color,
        val ctaBackground: Color,
        val sliderDotActive: Color,
        val cardBorder: Color,
        val tableHeaderBorder: Color,
        val tableRowBorder: Color,
        val applyButton: Color,
        val mutedText: Color,
        val partnerBorder: Color,
        val footerBackground: Color,
    )
}

