@InitRoute
fun initDirectionsPage(ctx: InitRouteContext) {
    ctx.data.add(PageLayoutData("찾아오시는 길"))
}

@Page("/directions")
@Layout(".components.layouts.PageLayout")
@Composable
fun DirectionsPage() {
    val ctx = rememberPageContext()
    SubPageScaffold(
        heroTitle = "찾아오시는길",
        heroSubtitle = "드론조종자교육/드론항공촬영/드론항공방제/드론정비/드론제작",
        heroImageUrl = "https://images.unsplash.com/photo-1473448912268-2022ce9509d8?auto=format&fit=crop&w=1800&q=80",
        sideTitle = "회사정보",
        sideMenus = listOf(
            SubPageMenuItem("연락처", "/contact", selected = false),
            SubPageMenuItem("찾아오시는길", "/directions", selected = true),
        ),
        contentTitle = "찾아오시는길",
        onMenuClick = { item -> ctx.router.tryRoutingTo(item.path) }
    ) {
        Column(
            Modifier.fillMaxWidth(),
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            SpanText(Config.SITE_NAME, Modifier.fontSize(1.95.cssRem).fontWeight(FontWeight.Bold))
            SpanText(
                "(사무실, 이론 및 모의비행 강의, 이론시험장소)",
                Modifier.fontSize(1.5.cssRem).fontWeight(FontWeight.SemiBold).margin(top = 0.4.cssRem, bottom = 1.2.cssRem)
            )
        }

        Box(
            Modifier
                .fillMaxWidth()
                .height(26.cssRem)
                .position(Position.Relative)
                .border(1.px, LineStyle.Solid, Color.rgb(0xDCDCDC))
        ) {
            KakaoMapBox()
            Box(
                Modifier
                    .position(Position.Absolute)
                    .top(1.cssRem)
                    .left(50.percent)
                    .translateX((-50).percent)
                    .backgroundColor(Color.rgba(255, 255, 255, 0.95f))
                    .padding(topBottom = 0.45.cssRem, leftRight = 0.9.cssRem)
                    .border(1.px, LineStyle.Solid, Color.rgb(0xDCDCDC))
            ) {
                Text(Config.COMPANY_ADDRESS)
            }
        }
    }
}
