@file:Suppress(
    "RETURN_VALUE_NOT_USED",
    "RETURN_VALUE_NOT_USED_COERCION",
)

import androidx.compose.runtime.Composable
import androidx.compose.runtime.ProvidableCompositionLocal
import androidx.compose.runtime.compositionLocalOf
import com.varabyte.kobweb.core.AppGlobals
import com.varabyte.kobweb.navigation.BasePath
import com.varabyte.kobweb.navigation.Router
import com.varabyte.kobweb.navigation.UpdateHistoryMode
import com.varabyte.kobweb.navigation.remove
import com.varabyte.kobweb.silk.defer.DeferringHost
import kotlin.Any
import kotlin.Suppress
import kotlin.Unit
import kotlinx.browser.document
import kotlinx.browser.window
import org.jetbrains.compose.web.renderComposable
import org.example.mmec.components.layouts.MarkdownLayout as _org_example_mmec_components_layouts_MarkdownLayout
import org.example.mmec.components.layouts.PageLayout as _org_example_mmec_components_layouts_PageLayout
import org.example.mmec.pages.AboutPage as _org_example_mmec_pages_AboutPage
import org.example.mmec.pages.ContactPage as _org_example_mmec_pages_ContactPage
import org.example.mmec.pages.DirectionsPage as _org_example_mmec_pages_DirectionsPage
import org.example.mmec.pages.HomePage as _org_example_mmec_pages_HomePage

private val LayoutScopeLocal: ProvidableCompositionLocal<Any?> = compositionLocalOf<Any?> { null }

@Composable
private fun <T : Any> currentLayoutScope(): T {
    @Suppress("UNCHECKED_CAST")
    return LayoutScopeLocal.current as? T
        ?: error("Unexpected between Page/Layout scope and the parent Layout which it is providing it. Please report this issue to the Kobweb developers.")
}

@Composable
private fun <T : Any> provideLayoutScope(layoutScope: T, content: @Composable () -> Unit) {
    androidx.compose.runtime.CompositionLocalProvider(LayoutScopeLocal provides layoutScope, content = content)
}

public fun main() {
    AppGlobals.initialize(mapOf("title" to "미래모빌리티전문교육원"))
    BasePath.set("")
    val router = Router()
    com.varabyte.kobweb.core.init.initKobweb(router) { ctx ->
        ctx.router.registerLayout(
            "org.example.mmec.components.layouts.MarkdownLayout",
            parentLayoutId = "org.example.mmec.components.layouts.PageLayout",
            initRouteMethod = { ctx ->
                org.example.mmec.components.layouts.initMarkdownLayout(ctx)
            },
        ) { pageCtx, pageMethod -> 
            _org_example_mmec_components_layouts_MarkdownLayout {
                pageMethod(pageCtx)
            }
        }
        ctx.router.registerLayout(
            "org.example.mmec.components.layouts.PageLayout",
        ) { pageCtx, pageMethod -> 
            _org_example_mmec_components_layouts_PageLayout(pageCtx) {
                provideLayoutScope(this) {
                    pageMethod(pageCtx)
                }
            }
        }
        ctx.router.register(
            "/",
            layoutId = "org.example.mmec.components.layouts.PageLayout",
            initRouteMethod = { ctx ->
                org.example.mmec.pages.initHomePage(ctx)
            },
        ) { pageCtx -> 
            _org_example_mmec_pages_HomePage()
        }
        ctx.router.register(
            "/about",
            layoutId = "org.example.mmec.components.layouts.MarkdownLayout",
            initRouteMethod = { ctx ->
                org.example.mmec.pages.initAboutPage(ctx)
            },
        ) { pageCtx -> 
            _org_example_mmec_pages_AboutPage()
        }
        ctx.router.register(
            "/contact",
            layoutId = "org.example.mmec.components.layouts.PageLayout",
            initRouteMethod = { ctx ->
                org.example.mmec.pages.initContactPage(ctx)
            },
        ) { pageCtx -> 
            _org_example_mmec_pages_ContactPage()
        }
        ctx.router.register(
            "/directions",
            layoutId = "org.example.mmec.components.layouts.PageLayout",
            initRouteMethod = { ctx ->
                org.example.mmec.pages.initDirectionsPage(ctx)
            },
        ) { pageCtx -> 
            _org_example_mmec_pages_DirectionsPage()
        }

    }
    router.addRouteInterceptor {
        path = path.removeSuffix(".html").removeSuffix(".htm")
    }

    com.varabyte.kobweb.silk.init.additionalSilkInitialization = { ctx ->
        com.varabyte.kobweb.silk.init.initSilkWidgets(ctx)
        com.varabyte.kobweb.silk.init.initSilkWidgetsKobweb(ctx)
        ctx.theme.registerStyle("headline-text", org.example.mmec.HeadlineTextStyle)
        ctx.theme.registerStyle("subheadline-text", org.example.mmec.SubheadlineTextStyle)
        ctx.theme.registerStyle("header-menu-item", org.example.mmec.components.sections.HeaderMenuItemStyle)
        ctx.theme.registerStyle("markdown", org.example.mmec.components.layouts.MarkdownStyle)
        ctx.theme.registerVariant("-circle", org.example.mmec.CircleButtonVariant
        )
        ctx.theme.registerVariant("-uncolored", org.example.mmec.UncoloredButtonVariant
        )
        org.example.mmec.initSiteStyles(ctx)
        org.example.mmec.initColorMode(ctx)
        org.example.mmec.initStyles(ctx)
        org.example.mmec.initTheme(ctx)
    }

    // Dedup any leading slashes after removing the origin, just in case someone typed
    // something like `https://site.com//about` by accident. If we pass `//about` into
    // `tryRoutingTo`, Kobweb will reject it as a protocol-relative URL; instead, we
    // want it to navigate to `/about`
    router.tryRoutingTo(BasePath.remove("/" + window.location.href.removePrefix(window.origin).trimStart('/')), UpdateHistoryMode.REPLACE)

    // For SEO, we may bake the contents of a page in at build time. However, we will
    // overwrite them the first time we render this page with their composable, dynamic
    // versions. Think of this as poor man's hydration :)
    // See also: https://en.wikipedia.org/wiki/Hydration_(web_development)
    val root = document.getElementById("_kobweb-root")!!
    while (root.firstChild != null) { root.removeChild(root.firstChild!!) }

    renderComposable(rootElementId = "_kobweb-root") {
        org.example.mmec.AppEntry {
            router.renderActivePage { DeferringHost { it() } }
        }
    }
}
